function HashSet(r,u){var o=new Hashtable(r,u);this.add=function(n){o.put(n,!0)},this.addAll=function(n){for(var t=0,e=n.length;t<e;++t)o.put(n[t],!0)},this.values=function(){return o.keys()},this.remove=function(n){return o.remove(n)?n:null},this.contains=function(n){return o.containsKey(n)},this.clear=function(){o.clear()},this.size=function(){return o.size()},this.isEmpty=function(){return o.isEmpty()},this.clone=function(){var n=new HashSet(r,u);return n.addAll(o.keys()),n},this.intersection=function(n){for(var t,e=new HashSet(r,u),i=n.values(),s=i.length;s--;)t=i[s],o.containsKey(t)&&e.add(t);return e},this.union=function(n){for(var t,e=this.clone(),i=n.values(),s=i.length;s--;)t=i[s],o.containsKey(t)||e.add(t);return e},this.isSubsetOf=function(n){for(var t=o.keys(),e=t.length;e--;)if(!n.contains(t[e]))return!1;return!0},this.complement=function(n){for(var t,e=new HashSet(r,u),i=this.values(),s=i.length;s--;)t=i[s],n.contains(t)||e.add(t);return e}}